import pytest
import requests

def test_requests_within_limit_all_succeed(fresh_user_token, base_url):
    endpoint = f"{base_url}/api/v1/accounts"
    headers = {"Authorization": f"Bearer {fresh_user_token}"}
    responses = [
        requests.get(endpoint, headers=headers, timeout=5)
        for _ in range(30)
    ]
    status_codes = [r.status_code for r in responses]
    assert all(sc == 200 for sc in status_codes), (
        f"Expected all 200, got: {set(status_codes)}"
    )
    retry_headers = [r.headers.get("Retry-After") for r in responses]
    assert all(h is None for h in retry_headers), (
        "Unexpected Retry-After header within allowed quota"
    )

import pytest
import requests

def test_61st_request_returns_429_with_retry_after(fresh_user_token, base_url):
    endpoint = f"{base_url}/api/v1/accounts"
    headers = {"Authorization": f"Bearer {fresh_user_token}"}
    for i in range(60):
        r = requests.get(endpoint, headers=headers, timeout=5)
        assert r.status_code in (200, 201, 204), (
            f"Request {i+1} failed unexpectedly: {r.status_code}"
        )
    overage = requests.get(endpoint, headers=headers, timeout=5)
    assert overage.status_code == 429, (
        f"Expected 429 on 61st request, got {overage.status_code}"
    )
    retry_after = overage.headers.get("Retry-After")
    assert retry_after is not None, "Retry-After header missing on 429 response"
    assert int(retry_after) > 0, (
        f"Retry-After must be a positive integer, got: {retry_after}"
    )

import pytest
import requests

def test_exactly_60th_request_is_allowed(fresh_user_token, base_url):
    endpoint = f"{base_url}/api/v1/accounts"
    headers = {"Authorization": f"Bearer {fresh_user_token}"}
    for i in range(59):
        r = requests.get(endpoint, headers=headers, timeout=5)
        assert r.status_code in (200, 201, 204), (
            f"Setup request {i+1} failed: {r.status_code}"
        )
    boundary = requests.get(endpoint, headers=headers, timeout=5)
    assert boundary.status_code in (200, 201, 204), (
        f"60th request (boundary) should succeed, got {boundary.status_code}"
    )
    assert boundary.headers.get("Retry-After") is None, (
        "Retry-After must not be present on the 60th (boundary) request"
    )
